import React, { Component } from 'react';
import { Link, withRouter } from 'react-router-dom';
import { connect } from 'react-redux';
import PropTypes from 'prop-types';
import s from '../Auth.module.scss';
import $ from 'jquery';
import ReactLoading from 'react-loading';

import { loginUser } from '../../../../redux/actions/authentication';

class Login extends Component {

    constructor(props) {
        super(props);
        this.state = {
            login: "",
            password: "",
            waiting: false
        };

        this.handleInputChange = this.handleInputChange.bind(this);
        this.submitForm = this.submitForm.bind(this);

        if (props.auth.isAuthenticated) {
            props.history.push('/');
        }
    }

    UNSAFE_componentWillReceiveProps(newProps) { 
        if (newProps.auth.isAuthenticated) {
            this.props.history.push('/');
        }

        if (newProps.errors !== undefined) {
            this.setState({ errors: newProps.errors, waiting: false });
        }
    }

    handleInputChange(e) {
        const current_target = [e.target.name].toString();
        this.setState({ [e.target.name]: e.target.value });

        const errors = this.state.errors;   
        if (errors !== undefined) {
            this.setState(prevState => ({
                errors: {     
                    ...prevState.errors, 
                    [current_target]: '',
                    general: ""
                }
            }))
        }
    }

    submitForm(e) {
        e.preventDefault();
        const user = {
            login: this.state.login,
            password: this.state.password
        }
        this.props.loginUser(user);
        this.setState({ waiting: true });
    }

    triggerFocus(e) {
        $(e.target).parent().addClass(s['form-group--active']);
    }

    removeFocus(e) {
        if (e.target.value == "") {
            $(e.target).parent().removeClass(s['form-group--active']);
        }
    }

    render() {
        const { errors, waiting } = this.state;

        return (
            <div className={s.background}>
                <div className={s.form}>
                    <div className={s.header}>
                        <h3>Log in</h3>
                        <Link to="/">Artly</Link>
                    </div>
                    <form onSubmit={this.submitForm} autoComplete="none">
                        <div className={s['form-group']}>
                            <input
                                type="text"
                                name="login"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.email}
                                className='bs-input'
                            />
                            <span>Username, Email address</span>
                            {(errors !== undefined && errors.login !== '') ? <p className={s['form-error']}>{errors.login}</p> : ''}
                        </div>
                        <div className={s['form-group']}>
                            <input
                                type="password"
                                name="password"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.password}
                                className='bs-input'
                            />
                            <img src=""/>
                            <span>Password</span>
                            {(errors !== undefined && errors.password !== '') ? <p className={s['form-error']}>{errors.password}</p> : ''}
                            {(errors !== undefined && errors.general !== '') ? <p className={s['form-error']}>{errors.general}</p> : ''}
                        </div>
                        <div className={[s['form-group'], s['form-group__submit']].join(' ')}>
                            <button type="submit" disabled={this.state.waiting}>{waiting ? <ReactLoading type="bars" color="#ffffff" height="auto" width="auto" /> : "Login"}</button>
                        </div>
                        <div className={s['form-group__final']}>
                            <p>Forgot your password? You can <Link to="/reset-password">reset it here.</Link></p>
                            <p>Don't have account? <Link to="/signup">Sign up now.</Link></p>
                        </div>
                    </form>
                </div>
            </div>
        )
    }
}

Login.propTypes = {
    auth: PropTypes.object,
    loginUser: PropTypes.func,
    errors: PropTypes.object.isRequired,
    history: PropTypes.object.isRequired
};

const mapStateToProps = (state) => ({
    auth: state.auth,
    errors: state.errors
});

export default withRouter(connect(mapStateToProps, { loginUser })(Login));
